import{_ as t,o as a,c as n,a2 as o}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 12 — Line Motions","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/12-line-motions.md","filePath":"chapters/12-line-motions.md"}'),i={name:"chapters/12-line-motions.md"};function s(r,e,d,l,c,h){return a(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="chapter-12-—-line-motions" tabindex="-1">Chapter 12 — Line Motions <a class="header-anchor" href="#chapter-12-—-line-motions" aria-label="Permalink to &quot;Chapter 12 — Line Motions&quot;">​</a></h1><blockquote><p><em>&quot;Lines are the fundamental unit of code. Moving to their edges is essential.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐ Beginner-Intermediate <strong>Estimated Reading Time:</strong> 10–15 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>After word motions, line motions are the next most important navigation skill.</p><p>They let you jump to the beginning, end, or logical start of any line.</p><hr><h1 id="the-four-line-motions" tabindex="-1">The Four Line Motions <a class="header-anchor" href="#the-four-line-motions" aria-label="Permalink to &quot;The Four Line Motions&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Motion</th><th>Action</th></tr></thead><tbody><tr><td><code>0</code></td><td>Jump to <strong>first column</strong> (column 0)</td></tr><tr><td><code>^</code></td><td>Jump to <strong>first non-whitespace</strong> character</td></tr><tr><td><code>$</code></td><td>Jump to <strong>end of line</strong></td></tr><tr><td><code>g_</code></td><td>Jump to <strong>last non-whitespace</strong> character</td></tr></tbody></table><hr><h1 id="visual-example" tabindex="-1">Visual Example <a class="header-anchor" href="#visual-example" aria-label="Permalink to &quot;Visual Example&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    Line: &quot;    hello world    &quot;</span></span>
<span class="line"><span>          ^</span></span>
<span class="line"><span>          │</span></span>
<span class="line"><span>          0 (column 0)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>              ^</span></span>
<span class="line"><span>              │</span></span>
<span class="line"><span>              ^ (first non-blank)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                      ^</span></span>
<span class="line"><span>                      │</span></span>
<span class="line"><span>                      g_ (last non-blank)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                                 ^</span></span>
<span class="line"><span>                                 │</span></span>
<span class="line"><span>                                 $ (end of line)</span></span></code></pre></div><hr><h1 id="when-to-use-each" tabindex="-1">When to Use Each <a class="header-anchor" href="#when-to-use-each" aria-label="Permalink to &quot;When to Use Each&quot;">​</a></h1><h2 id="_0-—-beginning-of-line" tabindex="-1"><code>0</code> — Beginning of Line <a class="header-anchor" href="#_0-—-beginning-of-line" aria-label="Permalink to &quot;\`0\` — Beginning of Line&quot;">​</a></h2><p>Use when you want to go to the absolute start.</p><p>Common before indentation-sensitive operations.</p><h2 id="—-first-non-blank-character" tabindex="-1"><code>^</code> — First Non-Blank Character <a class="header-anchor" href="#—-first-non-blank-character" aria-label="Permalink to &quot;\`^\` — First Non-Blank Character&quot;">​</a></h2><p>Use when you want to go to where the text actually begins.</p><p>This is the most commonly used line-start motion.</p><h2 id="—-end-of-line" tabindex="-1"><code>$</code> — End of Line <a class="header-anchor" href="#—-end-of-line" aria-label="Permalink to &quot;\`$\` — End of Line&quot;">​</a></h2><p>Use when you want to append text or delete to the end.</p><p>Equivalent to pressing End on a regular keyboard.</p><h2 id="g-—-last-non-blank-character" tabindex="-1"><code>g_</code> — Last Non-Blank Character <a class="header-anchor" href="#g-—-last-non-blank-character" aria-label="Permalink to &quot;\`g_\` — Last Non-Blank Character&quot;">​</a></h2><p>Use when you want to operate on the last real character.</p><p>Less common than <code>$</code>, but useful for precise editing.</p><hr><h1 id="combining-with-operators" tabindex="-1">Combining with Operators <a class="header-anchor" href="#combining-with-operators" aria-label="Permalink to &quot;Combining with Operators&quot;">​</a></h1><p>Line motions + operators = efficient line editing:</p><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>d0</code></td><td>Delete from cursor to beginning of line</td></tr><tr><td><code>d^</code></td><td>Delete from cursor to first non-blank</td></tr><tr><td><code>d$</code></td><td>Delete from cursor to end of line</td></tr><tr><td><code>c0</code></td><td>Change to beginning of line</td></tr><tr><td><code>c$</code></td><td>Change to end of line</td></tr><tr><td><code>y0</code></td><td>Yank to beginning of line</td></tr><tr><td><code>y$</code></td><td>Yank to end of line</td></tr></tbody></table><hr><h1 id="special-line-operations" tabindex="-1">Special Line Operations <a class="header-anchor" href="#special-line-operations" aria-label="Permalink to &quot;Special Line Operations&quot;">​</a></h1><h2 id="joining-lines" tabindex="-1">Joining Lines <a class="header-anchor" href="#joining-lines" aria-label="Permalink to &quot;Joining Lines&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>J</code></td><td>Join current line with next</td></tr><tr><td><code>gJ</code></td><td>Join without adding space</td></tr><tr><td><code>3J</code></td><td>Join 3 lines together</td></tr></tbody></table><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Line 1</span></span>
<span class="line"><span>Line 2</span></span></code></pre></div><p>Cursor on Line 1, press <code>J</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Line 1 Line 2</span></span></code></pre></div><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Motion</th><th>Position</th></tr></thead><tbody><tr><td><code>0</code></td><td>First column</td></tr><tr><td><code>^</code></td><td>First non-blank char</td></tr><tr><td><code>$</code></td><td>End of line</td></tr><tr><td><code>g_</code></td><td>Last non-blank char</td></tr></tbody></table><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li><code>0</code> goes to column 0; <code>^</code> goes to the first actual character.</li><li><code>$</code> goes to the end; <code>g_</code> goes to the last non-blank.</li><li>Combine with <code>d</code>, <code>c</code>, <code>y</code> to edit parts of a line.</li><li><code>J</code> joins lines together.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Open a file with indented code and practice <code>0</code> vs <code>^</code> to see the difference.</li><li>Use <code>d$</code> to delete from the cursor to the end of a line.</li><li>Use <code>c0</code> to change from the cursor to the beginning.</li><li>Practice <code>J</code> to join multiple lines.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./13-file-motions.html"><strong>Chapter 13 — File Motions</strong></a></p><p>Navigate across an entire file in seconds using jumps and scroll commands.</p>`,53)])])}const m=t(i,[["render",s]]);export{u as __pageData,m as default};
